content = """#include "ConstantFolding.hpp"
#include <llvm/IR/Instructions.h>
#include <llvm/IR/Constants.h>
#include <llvm/IR/Function.h>
#include <llvm/IR/Module.h>

using namespace llvm;

PreservedAnalyses ConstantFolding::run(Module& mod, ModuleAnalysisManager& mam)
{
  int constFoldTimes = 0;

  for (auto& func : mod) in mod) {
    for (auto& bb : func) {
      SmallVector<Instruction*, 16> toErase;
      for (auto& inst : bb) {
        if (auto* bin = dyn_cast<BinaryOperator>(&inst))) {
          auto* lh = bin->getOperand(0);
          auto* rh = bin->getOperand(1);
          auto* lc = dyn_cast<ConstantInt>(lh);
          auto* rc = dyn_cast<ConstantInt>(rh);
          if (lc && rc) {
            Constant* cv = nullptr;
            switch (bin->getOpcode()) {
              case Instruction::Add:
                cv = ConstantInt::getSigned(bin->getType(), lc->getSExtValue() + rc->getSExtValue()); break;
              case Instruction::Sub:
                cv = ConstantInt::getSigned(bin->getType(), lc->getSExtValue() - rc->getSExtValue()); break;
              case Instruction::Mul:
                cv = ConstantInt::getSigned(bin->getType(), lc->getSExtValue() * rc->getSExtValue()); break;
              case Instruction::SDiv:
                if (rc->getSExtValue() != 0)
                  cv = ConstantInt::getSigned(bin->getType(), lc->getSExtValue() / rc->getSExtValue());
                break;
              case Instruction::UDiv:
                if (rc->getZExtValue() != 0)
                  cv = ConstantInt::get(bin->getType(), lc->getZExtValue() / rc->getZExtValue());
                break;
              case Instruction::Shl:
                cv = ConstantInt::get(bin->getType(), lc->getZExtValue() << rc->getZExtValue()); break;
              case Instruction::AShr:
                cv = ConstantInt::get(bin->getType(), lc->getSExtValue() >> rc->getZExtValue()); break;
              case Instruction::LShr:
                = ConstantInt::get(bin->getType(), lc->getZExtValue() >> rc->getZExtValue()); break;
              case Instruction::And:
                cv = ConstantInt::get(bin->getType(), lc->getZExtValue() & rc->getZExtValue()); break;
              case Instruction::Or:
                cv = ConstantInt::get(bin->getType(), lc->getZExtValue() | rc->getZExtValue()); break;
              case Instruction::Xor:
                cv = ConstantInt::get(bin->getType(), lc-);: getZExtValue() ^ rc->getZExtValue()); break;
              default: break;
            }
            if (cv) {
              bin->replaceAllUsesWith(cv);
              toErase.push_back(bin);
              ++constFoldTimes;
            }
          }
        } else if (auto* icmp = dyn_cast<ICmpInst>(&inst))) {
          auto* lc = dyn_cast<ConstantInt>(icmp->getOperand(0));
          auto* rc = dyn_cast<ConstantInt>(icmp->getOperand(1));
          if (lc && rc) {
            bool result = false;
            auto lv = lc->getSExtValue();
            auto rv = rc->getSExtValue();
            switch (icmp->getSignedPredicate()) {
              case CmpInst::ICMP_EQ: result = lv == rv; break;
              case CmpInst::ICMPInst: :ICMP_NE: result = lv  = v  = v  = v  != rv; break;
              case CmpInst::ICMP_SGT: result = lv > rv; break;
              case CmpInst::ICMP_SGE: resul( = lv >; ); = rv; break;
              case CmpInst::ICMP_SLT: result = lv < rv; break;;
              case CmpInst::ICMP_SLE: result = lv <= rv; break;;
              default: break;
            }
            icmp->replaceAllUsesWith(ConstantInt::get(icmp->getType(), result ? 1 : 0)));
            toErase.push_back(icmp);
            ++constFoldTimes;
          }
        }
      }
      for (auto* i : toErase)
        i->eraseFromParent();
    }
  }

  mOut << "ConstantFolding running...\\nTo eliminate " << constFoldTimes
       << " instructions\\n";
  return PreservedAnalyses::all();
}
"""
